module top_module(input wire [3:0] in, input wire [1:0] s, output wire out);reg [3:0] unused_temp;
    always @(in or s)
        case (s)
            2'b00: unused_temp = in[0];
            2'b01: unused_temp = in[1];
            2'b10: unused_temp = in[2];
            2'b11: unused_temp = in[3];
            default: unused_temp = 4'b0;
        endcase
    assign out = unused_temp;
endmodule
